import React, { useState, useEffect, useCallback } from 'react';
import {
  CreditCard, DollarSign, AlertTriangle, FileText,
  Play, CheckCircle, Download, Plus, RefreshCw,
  TrendingUp, Users, Zap, ShieldCheck, Database,
  Globe, Scale, Save, Lock, Settings, Calculator, 
  Receipt, Clock, Check, X
} from 'lucide-react';
import toast from 'react-hot-toast';
import { payrollAPI } from '../../api/services'; // Ensure this has actionReimbursement
import { Badge, SkeletonCard, SkeletonTable, Modal, InlineSpinner } from '../../components/common';
import { useAuth } from '../../context/AuthContext';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, LineChart, Line } from 'recharts';

/* ── Dashboard KPI card ── */
function PayKPI({ icon: Icon, label, value, color, sub }) {
  return (
    <div className="stat-card">
      <div className="stat-card-accent" style={{ background: color }} />
      <div className="stat-card-icon" style={{ background: `${color}22` }}>
        <Icon size={20} style={{ color }} />
      </div>
      <div className="stat-card-value">{value ?? '—'}</div>
      <div className="stat-card-label">{label}</div>
      {sub && <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: 3 }}>{sub}</div>}
    </div>
  );
}

/* ── Payslip viewer ── */
function PayslipModal({ payslip, onClose }) {
  if (!payslip) return null;
  const financialData = payslip?.Entry || payslip || {};
  const runData = payslip?.PayrollRun || payslip || {};
  const lines = financialData?.Lines || [];
  const fmt = (v) => Number(v).toLocaleString('en-US', { style: 'currency', currency: 'EGP' });
  const startDate = runData?.PeriodStartDate || runData?.payPeriodStart || payslip?.IssueDate;
  const endDate = runData?.PeriodEndDate || runData?.payPeriodEnd;
  const status = payslip?.Status || payslip?.status || 'Finalized';

  return (
    <Modal open={!!payslip} onClose={onClose} title="Payslip Details" size="modal-lg">
      <div style={{ background: 'var(--bg-base)', border: '1px solid var(--border)', borderRadius: 'var(--radius-lg)', padding: 24, marginBottom: 16 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 20 }}>
          <div>
            <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.1rem', fontWeight: 700 }}>Official Payslip</div>
            <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
              Period: {startDate ? `${new Date(startDate).toLocaleDateString()} – ${endDate ? new Date(endDate).toLocaleDateString() : 'Present'}` : '—'}
            </div>
          </div>
          <Badge status={status}>{status}</Badge>
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
          <div>
            <div style={{ fontSize: '0.72rem', fontWeight: 600, color: 'var(--green)', textTransform: 'uppercase', marginBottom: 8 }}>Earnings</div>
            {lines.filter(l => Number(l.Amount || l.amount) > 0).map((line, idx) => (
              <div key={idx} style={{ display: 'flex', justifyContent: 'space-between', padding: '5px 0', borderBottom: '1px solid var(--border-light)' }}>
                <span style={{ fontSize: '0.82rem' }}>{line.Description || line.description}</span>
                <span>{fmt(Math.abs(line.Amount || line.amount))}</span>
              </div>
            ))}
          </div>
          <div>
            <div style={{ fontSize: '0.72rem', fontWeight: 600, color: 'var(--red)', textTransform: 'uppercase', marginBottom: 8 }}>Deductions</div>
            {lines.filter(l => Number(l.Amount || l.amount) < 0).map((line, idx) => (
              <div key={idx} style={{ display: 'flex', justifyContent: 'space-between', padding: '5px 0', borderBottom: '1px solid var(--border-light)' }}>
                <span style={{ fontSize: '0.82rem' }}>{line.Description || line.description}</span>
                <span style={{ color: 'var(--red)' }}>{fmt(Math.abs(line.Amount || line.amount))}</span>
              </div>
            ))}
          </div>
        </div>
        <div style={{ marginTop: 16, padding: 16, background: 'var(--gold-glow)', borderRadius: 8, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span style={{ fontWeight: 600 }}>FINAL NET PAY</span>
          <span style={{ fontSize: '1.4rem', fontWeight: 700, color: 'var(--gold)' }}>{fmt(financialData.NetPay || 0)}</span>
        </div>
      </div>
    </Modal>
  );
}

export default function PayrollPage() {
  const { user } = useAuth();
  const isAdmin = ['Payroll', 'HR', 'Admin'].includes(user?.role);
  const isLegal = ['Admin', 'Legal'].includes(user?.role);

  const [tab, setTab] = useState(isAdmin ? 'dashboard' : 'myslips');
  const [dashboard, setDash] = useState(null);
  const [runs, setRuns] = useState([]);
  const [myPayslips, setMySlips] = useState([]);
  const [exceptions, setExcept] = useState([]);
  const [claims, setClaims] = useState([]);
  const [selectedSlip, setSlip] = useState(null);
  const [loadDash, setLoadDash] = useState(true);
  const [loadRuns, setLoadRuns] = useState(true);
  const [createRunModal, setCreateRunModal] = useState(false);
  const [claimModal, setClaimModal] = useState(false);
  const [saving, setSaving] = useState(false);

  const [editPolicyModal, setEditPolicyModal] = useState(false);
  const [editGradeModal, setEditGradeModal] = useState(false);
  const [editTaxModal, setEditTaxModal] = useState(false);
  const [configForm, setConfigForm] = useState({ minWage: 6000, workDays: 22 });
  const [legalForm, setLegalForm] = useState({ siRate: 7.25 });
  const [runForm, setRunForm] = useState({ PolicyID: 1, PeriodStartDate: '', PeriodEndDate: '' });
  const [claimForm, setClaimForm] = useState({ type: 'Transport', amount: '', reason: '' });

  const load = useCallback(() => {
    const extract = (res) => {
      let payload = res;
      if (payload && payload.data !== undefined) payload = payload.data;
      if (payload && payload.success !== undefined && payload.data !== undefined) payload = payload.data;
      return payload || null;
    };

    // Employee features
    payrollAPI.getMyPayslips().then(res => setMySlips(extract(res)?.payslips || extract(res) || [])).catch(() => {});
    payrollAPI.listReimbursements().then(res => setClaims(extract(res) || [])).catch(() => {});

    // Admin/Specialist features
    if (isAdmin) {
      payrollAPI.getDashboard().then(res => { setDash(extract(res)); setLoadDash(false); }).catch(() => setLoadDash(false));
      payrollAPI.listRuns({ limit: 10 }).then(res => { 
        const data = extract(res);
        setRuns(Array.isArray(data) ? data : (data?.runs || []));
        setLoadRuns(false); 
      }).catch(() => setLoadRuns(false));
      payrollAPI.listExceptions().then(res => { 
        const data = extract(res);
        setExcept(Array.isArray(data) ? data : (data?.exceptions || [])); 
      }).catch(() => {});
    } else {
      setLoadDash(false); setLoadRuns(false);
    }
  }, [isAdmin]);

  useEffect(() => { load(); }, [load]);

  const handleSubmitClaim = async () => {
    if (!claimForm.amount || !claimForm.reason) return toast.error("Please fill in all fields");
    setSaving(true);
    try {
      await payrollAPI.submitReimbursement({
        type: claimForm.type,
        amount: parseFloat(claimForm.amount),
        reason: claimForm.reason
      });
      toast.success("Claim submitted");
      setClaimModal(false);
      setClaimForm({ type: 'Transport', amount: '', reason: '' });
      load();
    } catch (err) { toast.error("Submission failed"); } finally { setSaving(false); }
  };

  const handleActionClaim = async (id, status) => {
    try {
      // Use the service directly to ensure path prefix is correct
      await payrollAPI.actionReimbursement(id, { 
        status: status,
        ResolutionNotes: `Claim ${status} by ${user.role}` 
      }); 
      toast.success(`Claim ${status}`);
      load();
    } catch (err) { toast.error("Update failed"); }
  };

  const handleRunAction = async (runId, action) => {
    try {
      if (action === 'process') await payrollAPI.processRun(runId, {});
      if (action === 'approve') await payrollAPI.approveRun(runId, {});
      if (action === 'finalize') await payrollAPI.finalizeRun(runId);
      if (action === 'payslips') await payrollAPI.generatePayslips(runId);
      toast.success(`Run ${action}d successfully`);
      load();
    } catch (err) { toast.error('Action failed'); }
  };

  const handleCreateRun = async () => {
    setSaving(true);
    try {
      await payrollAPI.createRun({
        PolicyID: Number(runForm.PolicyID),
        PeriodStartDate: new Date(runForm.PeriodStartDate).toISOString(),
        PeriodEndDate: new Date(runForm.PeriodEndDate).toISOString(),
      });
      toast.success('Run created');
      setCreateRunModal(false);
      load();
    } catch (err) { toast.error('Failed to create run'); } finally { setSaving(false); }
  };

  const handleResolveException = async (id) => {
    try {
      await payrollAPI.resolveException(id, { resolution: 'Resolved', ResolutionNotes: 'Resolved via UI' });
      toast.success('Exception resolved');
      load();
    } catch (err) { toast.error('Failed to resolve'); }
  };

  const handleBackup = () => {
    const data = JSON.stringify({ runs, timestamp: new Date() });
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `payroll_backup.json`;
    link.click();
    toast.success("Backup Created");
  };

  const TABS = [
    ...(isAdmin ? [{ id: 'dashboard', label: 'Dashboard' }] : []),
    { id: 'myslips', label: 'My Payslips' },
    { id: 'claims', label: 'Reimbursements' },
    ...(isAdmin ? [
      { id: 'runs', label: 'Payroll Runs' },
      { id: 'exceptions', label: `Exceptions (${exceptions.length})` },
      { id: 'config', label: 'System Config' },
    ] : []),
    ...(isLegal ? [{ id: 'legal', label: 'Legal & Compliance' }] : [])
  ];

  const fmt = (v) => v != null ? Number(v).toLocaleString('en-US', { style: 'currency', currency: 'EGP', maximumFractionDigits: 0 }) : '—';

  const chartData = (dashboard?.MonthlySummary || []).map(d => ({
    month: d.Month || d.month,
    netPay: d.NetPay || d.netPay,
    grossPay: d.GrossPay || d.grossPay
  }));

  return (
    <>
      <div className="page-header">
        <h1>Payroll Engine</h1>
        <p>Manage salary cycles and handle reimbursement claims</p>
      </div>

      <div className="tabs">
        {TABS.map(({ id, label }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}>{label}</button>
        ))}
      </div>

      {/* ── Dashboard (Admin Only) ── */}
      {tab === 'dashboard' && isAdmin && (
        <div className="grid-4">
          <PayKPI icon={DollarSign} color="var(--green)" label="Total Payroll" value={fmt(dashboard?.TotalNetAmount)} />
          <PayKPI icon={Users} color="var(--blue)" label="Employees Paid" value={dashboard?.TotalEmployees} />
          <PayKPI icon={RefreshCw} color="var(--gold)" label="Active Runs" value={dashboard?.ActiveRuns} />
          <PayKPI icon={AlertTriangle} color="var(--red)" label="Open Issues" value={exceptions.length} />
        </div>
      )}

      {/* ── My Payslips ── */}
      {tab === 'myslips' && (
        <div className="table-wrap">
          <table>
            <thead><tr><th>Period</th><th>Gross Pay</th><th>Deductions</th><th>Net Pay</th><th>Status</th><th></th></tr></thead>
            <tbody>
              {myPayslips.map((slip, i) => (
                <tr key={i}>
                  <td>{new Date(slip.PayrollRun?.PeriodStartDate || slip.IssueDate).toLocaleDateString()}</td>
                  <td>{fmt(slip.Entry?.TotalEarnings)}</td>
                  <td>{fmt(slip.Entry?.TotalDeductions)}</td>
                  <td style={{ fontWeight: 700 }}>{fmt(slip.Entry?.NetPay)}</td>
                  <td><Badge status={slip.Status || 'Finalized'}>{slip.Status || 'Finalized'}</Badge></td>
                  <td><button className="btn btn-ghost btn-sm" onClick={() => setSlip(slip)}>View</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* ── Reimbursements ── */}
      {tab === 'claims' && (
        <div className="table-wrap">
          <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: 12 }}>
            <button className="btn btn-primary btn-sm" onClick={() => setClaimModal(true)}><Plus size={14}/> New Claim</button>
          </div>
          <table>
            <thead><tr><th>Employee</th><th>Date</th><th>Category</th><th>Amount</th><th>Status</th><th>Action</th></tr></thead>
            <tbody>
              {claims.length === 0 ? (
                <tr><td colSpan="6" style={{ textAlign: 'center', padding: 24 }}>No claims found.</td></tr>
              ) : (
                claims.map(c => (
                  <tr key={c.ClaimID || c.id}>
                    <td>{c.Employee?.FullName || user.fullName}</td>
                    <td>{new Date(c.CreatedAt || Date.now()).toLocaleDateString()}</td>
                    <td>{c.Category || c.type}</td>
                    <td>{fmt(c.Amount || c.amount)}</td>
                    <td><Badge status={c.Status || c.status}>{c.Status || c.status}</Badge></td>
                    <td>
                      {isAdmin && (c.Status === 'Pending') && (
                        <div style={{display:'flex', gap: 4}}>
                           <button className="btn btn-success btn-xs" onClick={() => handleActionClaim(c.ClaimID || c.id, 'Approved')}><Check size={12}/></button>
                           <button className="btn btn-red btn-xs" onClick={() => handleActionClaim(c.ClaimID || c.id, 'Rejected')}><X size={12}/></button>
                        </div>
                      )}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      {/* ── System Config ── */}
      {tab === 'config' && isAdmin && (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: 24 }}>
          <div className="card">
            <div className="card-header"><div className="card-title">Global Policies</div></div>
            <div className="card-body">
              <div className="form-group"><label className="form-label">Min Wage Cap: <strong>{configForm.minWage} EGP</strong></label></div>
              <button className="btn btn-primary btn-sm w-full" onClick={() => setEditPolicyModal(true)}>Edit</button>
            </div>
          </div>
        </div>
      )}

      {/* ── Payroll Runs ── */}
      {tab === 'runs' && isAdmin && (
        <div className="table-wrap">
          <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: 12 }}>
            <button className="btn btn-primary btn-sm" onClick={() => setCreateRunModal(true)}><Plus size={16} /> New Run</button>
          </div>
          <table>
            <thead><tr><th>ID</th><th>Period</th><th>Status</th><th>Net</th><th>Action</th></tr></thead>
            <tbody>
              {runs.map((r, i) => (
                <tr key={i}>
                  <td>#{r.PayrollRunID}</td>
                  <td>{new Date(r.PeriodStartDate).toLocaleDateString()}</td>
                  <td><Badge status={r.Status}>{r.Status}</Badge></td>
                  <td>{fmt(r.TotalNetAmount)}</td>
                  <td><button className="btn btn-ghost btn-sm" onClick={() => handleRunAction(r.PayrollRunID, 'process')}>Process</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <Modal open={claimModal} onClose={() => setClaimModal(false)} title="New Claim">
        <div className="form-group"><label className="form-label">Category</label>
          <select className="form-input" value={claimForm.type} onChange={e => setClaimForm({...claimForm, type: e.target.value})}>
            <option value="Transport">Transport</option><option value="Education">Education</option><option value="Travel">Travel</option>
          </select>
        </div>
        <div className="form-group"><label className="form-label">Amount</label><input type="number" className="form-input" value={claimForm.amount} onChange={e => setClaimForm({...claimForm, amount: e.target.value})} /></div>
        <div className="form-group"><label className="form-label">Reason</label><textarea className="form-input" value={claimForm.reason} onChange={e => setClaimForm({...claimForm, reason: e.target.value})} /></div>
        <button className="btn btn-primary w-full" onClick={handleSubmitClaim} disabled={saving}>Submit</button>
      </Modal>

      <Modal open={createRunModal} onClose={() => setCreateRunModal(false)} title="New Cycle">
        <div className="form-group"><label className="form-label">Policy ID</label><input className="form-input" type="number" value={runForm.PolicyID} onChange={e => setRunForm({...runForm, PolicyID: e.target.value})} /></div>
        <button className="btn btn-primary w-full" onClick={handleCreateRun}>Create</button>
      </Modal>

      <PayslipModal payslip={selectedSlip} onClose={() => setSlip(null)} />
    </>
  );
}
